Ok, I think I got it.

This is a preview of what I've done to use this new dict

```python
class LinkCol(Col):
    """Format the content as a link. Requires a endpoint to use to find
    the url and can also take a dict of url_kwargs which is expected
    to have values that are strings which are used to get data from
    the item.

    Eg:

    view = LinkCol('View', 'view_fn', url_kwargs=dict(id='id'))

    This will create a link to the address given by url_for('view_fn',
    id=item.id) for each item in the iterable.
    
    The dict url_kwargs_extra can be used to specify other link param 
    not in the item.

    Eg:

    view = LinkCol('View', 'view_fn', url_kwargs=dict(id='id'),
                                      url_kwargs_extra=dict(foo='bar'))

    This will create a link to the address given by url_for('view_fn',
    id=item.id, foo='bar') for each item in the iterable.

    """
    def __init__(self, name, endpoint, attr=None, attr_list=None,
                 url_kwargs=None, url_kwargs_extras=None, **kwargs):
        Col.__init__(self, name, attr=attr, attr_list=attr_list, **kwargs)
        self.endpoint = endpoint
        if url_kwargs is None:
            self._url_kwargs = {}
        else:
            self._url_kwargs = url_kwargs

        if url_kwargs_extras is None:
            self._url_kwargs_extras = {}
        else:
            self._url_kwargs_extras = url_kwargs_extras

    def url_kwargs(self, item):

        item_args = {k: _recursive_getattr(item, v)
                for k, v in self._url_kwargs.items()}

        extra_args = {k: v for k, v in self._url_kwargs_extras.items()}

        extra_args.update(item_args)
        
        return extra_args

    def get_attr_list(self, attr):
        return Col.get_attr_list(self, None)

    def text(self, item, attr_list):
        if attr_list:
            return self.from_attr_list(item, attr_list)
        else:
            return self.name

    def url(self, item):
        return url_for(self.endpoint, **self.url_kwargs(item))

    def td_contents(self, item, attr_list):
        return '<a href="{url}">{text}</a>'.format(
            url=self.url(item),
            text=self.td_format(self.text(item, attr_list)))
```

