Create test_resources.py with the following contents, create dir structure like this:

- ~/luigi_workflows/
    - test_resources.py
    - test_output/ (empty dir)

```
import os
import time

import luigi

# To run:
# pythonpath=.. luigi --module=luigi_workflows.test_resources ManyMany --workers=100

class Sleep(luigi.Task):
    resources = {'foo': 10}

    fname = luigi.Parameter()

    def requires(self):
        []

    def full_path(self):
        return os.path.join(os.path.dirname(os.path.realpath(__file__)), 'test_output', self.fname)

    def run(self):
        time.sleep(1)
        with open(self.full_path(), 'w') as f:
            print('', file=f)

    def output(self):
        return luigi.LocalTarget(self.full_path())


class Many(luigi.WrapperTask):
    prefix = luigi.Parameter()
    n = luigi.IntParameter()

    def requires(self):
        for i in range(self.n):
            yield Sleep(fname='marker_{}_{}'.format(self.prefix, i))


class ManyMany(luigi.WrapperTask):
    n = luigi.IntParameter(default=20)

    def requires(self):
        for prefix in ['a', 'b', 'c']:
            for i in range(self.n):
                yield Many(prefix=prefix, n=self.n)

```

My config file's resources section looks like this:

